// Token refresh endpoint
app.post('/auth/refresh', isAuthenticated, async (req, res) => {
  try {
    const refreshToken = req.session.tokens && req.session.tokens.refreshToken;

    if (!refreshToken) {
      return res.status(400).json({ error: 'No refresh token available' });
    }

    const tokenResponse = await axios.post(
      OIDC_CONFIG.tokenEndpoint,
      new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret,
      }).toString(),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        timeout: 10000,
      }
    );

    const { access_token, id_token, refresh_token: new_refresh_token, expires_in } = tokenResponse.data;

    // If a new id_token is provided, verify and update claims
    if (id_token) {
      const claims = await verifyIdToken(id_token);
      validateClaims(claims);

      req.session.user = {
        ...req.session.user,
        email: claims.email || req.session.user.email,
        name: claims.name || req.session.user.name,
      };
    }

    // Update tokens in session
    req.session.tokens = {
      accessToken: access_token,
      refreshToken: new_refresh_token || refreshToken,
      tokenType: 'Bearer',
      expiresIn: expires_in,
    };
    req.session.tokenExpiry = expires_in ? Date.now() + (expires_in * 1000) : null;

    res.json({
      message: 'Token refreshed successfully',
      expiresIn: expires_in,
    });
  } catch (error) {
    console.error('Token refresh failed:', error.message);
    res.status(500).json({ error: 'Token refresh failed' });
  }
});

